def prob_ge(w,p):
    n=len(w)
    tot=0
    for mask in range(1<<n):
        s=0; k=0
        for i in range(n):
            if mask>>i&1:
                s+=w[i]; k+=1
        if s>=p-1e-12:
            tot+=p**k*(1-p)**(n-k)
    return tot
