from itertools import combinations
def all_downsets(n):
    # generate antichains recursively? For n<=5 use monotone Boolean functions brute? Use previous maybe.
    # recursive: downset D on n from pair (D0,D1), D1 subset D0 downsets on n-1.
    if n==0:
        return [frozenset([0])] # masks
    prev=all_downsets(n-1)
    res=[]
    for D0 in prev:
        for D1 in prev:
            if D1.issubset(D0):
                D=set(D0)
                D.update({mask | (1<<(n-1)) for mask in D1})
                res.append(frozenset(D))
    # unique
    return list(set(res))
